// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "./Ownable.sol";

abstract contract VoterRegistry is Ownable {
    // 1. Структура виборця
    struct Voter {
        uint id;
        bool isRegistered; // Прапорець: чи зареєстрований виборець admin-ом
        bool hasVoted;     // Прапорець: чи вже віддав він свій голос
    }

    // Лічильник для створення унікальних ID виборців
    uint public voterCount;

    // 2. Mapping для зберігання інформації про виборців за їхніми адресами
    mapping(address => Voter) public voters;

    // 3. Подія реєстрації нового виборця
    event VoterRegistered(address indexed voterAddress, uint id);

    // 4. Внутрішня функція реєстрації виборця
    function _registerVoter(address voterAddress) internal {
        // Перевіряємо, щоб адреса не була нульовою і виборець не був зареєстрований раніше
        require(voterAddress != address(0), "Invalid voter address");
        require(!voters[voterAddress].isRegistered, "Voter already registered");

        voterCount++; // Збільшуємо лічильник для нового ID

        // Записуємо дані у mapping
        voters[voterAddress] = Voter({
            id: voterCount,
            isRegistered: true,
            hasVoted: false
        });

        // Генеруємо подію реєстрації
        emit VoterRegistered(voterAddress, voterCount);
    }
}

contracts/Ownable.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28; // Використовуємо версію як у вашому Counter.sol

abstract contract Ownable {
    // 1. Змінна для зберігання адреси власника
    address public owner;

    // 2. Подія, яка спрацьовує при зміні або встановленні власника
    event OwnerChanged(address indexed oldOwner, address indexed newOwner);

    // 3. Конструктор встановлює першого власника (того, хто робить деплой)
    constructor() {
        owner = msg.sender;
        emit OwnerChanged(address(0), msg.sender);
    }

    // 4. Модифікатор, який обмежує доступ до функцій (лише для owner)
    modifier onlyOwner() {
        require(msg.sender == owner, "Not an owner");
        _;
    }
}
